-- ── Helper functions ──
CREATE OR REPLACE FUNCTION _resolve_building(p_name TEXT)
RETURNS BIGINT AS $$
DECLARE v_id BIGINT;
BEGIN
    SELECT id INTO v_id FROM buildings WHERE name = p_name;
    IF v_id IS NULL THEN
        RAISE EXCEPTION 'Building not found: %', p_name;
    END IF;
    RETURN v_id;
END;
$$ LANGUAGE plpgsql;

CREATE OR REPLACE FUNCTION _resolve_room(p_building TEXT, p_room TEXT)
RETURNS BIGINT AS $$
DECLARE
    v_building_id BIGINT;
    v_room_id BIGINT;
BEGIN
    SELECT id INTO v_building_id FROM buildings WHERE name = p_building;
    IF v_building_id IS NULL THEN
        RAISE EXCEPTION 'Building not found: %', p_building;
    END IF;
    SELECT id INTO v_room_id FROM rooms WHERE building_id = v_building_id AND room_number = p_room;
    IF v_room_id IS NULL THEN
        RETURNING id INTO v_room_id;
    END IF;
    RETURN v_room_id;
END;
$$ LANGUAGE plpgsql;

-- ── Contracts (488 rows) ──
CREATE TEMP TABLE _tmp_contracts (
    orig_id INT, name TEXT, building TEXT, room TEXT, phone TEXT,
    rent BIGINT, mgmt BIGINT, deposit BIGINT, type TEXT, due TEXT,
    status TEXT, overdue BIGINT, move_in DATE, expiry DATE,
    prev_unpaid BIGINT, current_unpaid BIGINT, overdue_days INT,
    car_number TEXT, car_type TEXT
);

;

SELECT
    t.orig_id,
    _resolve_building(t.building),
    _resolve_room(t.building, t.room),
    t.name, t.phone, t.rent, t.mgmt, t.deposit, t.type, t.due,
    t.status, t.overdue, t.move_in, t.expiry, t.prev_unpaid,
    t.current_unpaid, t.overdue_days, t.car_number, t.car_type
FROM _tmp_contracts t;

SELECT setval('contracts_id_seq', (SELECT MAX(id) FROM contracts));
DROP TABLE _tmp_contracts;

